        </label>
        <label>
            Max:
            <input type="number" min="0" step="0.01"
                   value="@MaxPrice"
                   @onchange="@(e => MaxPrice = ParseDecimal(e.Value))" />
        </label>
    </div>

    <div class="filter-section">
        <label class="filter-checkbox">
            <input type="checkbox"
                   checked="@InStockOnly"
                   @onchange="@(e => InStockOnly = (bool)e.Value!)" />
            In Stock Only
        </label>
    </div>

